import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function GET() {
  try {
    const roles =
      await prisma.roles.findMany({
        orderBy: {
          id: "asc",
        },
      });

    return NextResponse.json(roles);

  } catch (error) {
    console.error(error);

    return NextResponse.json(
      [],
      { status: 500 }
    );
  }
}
